static bool controller_expire_stale_sensors(controller_t *controller, uint32_t now_ms)
{
    bool expired = false;

    if (controller == 0) {
        return false;
    }

    if (controller_sensor_is_stale(controller->has_valid_pressure, now_ms, controller->last_pressure_ms)) {
        if (controller->has_valid_pressure) {
            expired = true;
        }
        controller->has_valid_pressure = false;
    }

    if (controller_sensor_is_stale(controller->has_valid_door, now_ms, controller->last_door_ms)) {
        if (controller->has_valid_door) {
            expired = true;
        }
        controller->has_valid_door = false;
    }

    return expired;
}

